1	import { FileRepository, TransferSessionRepository, ChunkRepository } from '$lib/db';
2	import { validateFileIngest } from '$lib/validators';
3	import { ValidationServiceError } from '$lib/services/errors';
4	import { createLogger } from '$lib/logging';
5	import { arrayBufferToBase64 } from '$lib/security/crypto';
6	import { FILE_CHUNK_SIZE } from '$lib/constants';
7	import { TransferState } from '$lib/types/enums';
8	import type { FileRecord, TransferSession } from '$lib/types/files';
9	
10	const fileRepo = new FileRepository();
11	const transferRepo = new TransferSessionRepository();
12	const chunkRepo = new ChunkRepository();
13	const logger = createLogger('files');
14	
15	export async function computeHash(data: ArrayBuffer): Promise<string> {
16	  const hashBuffer = await crypto.subtle.digest('SHA-256', data);
17	  const hashArray = new Uint8Array(hashBuffer);
18	  return Array.from(hashArray).map(b => b.toString(16).padStart(2, '0')).join('');
19	}
20	
21	export async function checkDedup(sha256: string): Promise<{ exists: boolean; fileId?: string }> {
22	  const existing = await fileRepo.getByHash(sha256);
23	  const active = existing.find(f => !f.isDeleted);
24	  if (active) {
25	    return { exists: true, fileId: active.id };
26	  }
27	  return { exists: false };
28	}
29	
30	export async function ingestFile(
31	  fileName: string,
32	  fileSize: number,
33	  mimeType: string,
34	  fileData: ArrayBuffer,
35	  createdBy: string,
36	): Promise<{ file: FileRecord; session: TransferSession | null; deduplicated: boolean }> {
37	  const validation = validateFileIngest({ name: fileName, size: fileSize, type: mimeType });
38	  if (!validation.valid) throw new ValidationServiceError('Invalid file', validation.errors);
39	
40	  const sha256 = await computeHash(fileData);
41	
42	  // Check deduplication
43	  const dedup = await checkDedup(sha256);
44	  if (dedup.exists && dedup.fileId) {
45	    const existingFile = await fileRepo.getById(dedup.fileId);
46	    if (existingFile) {
47	      logger.info('File deduplicated', { fileName, sha256 });
48	      return { file: existingFile, session: null, deduplicated: true };
49	    }
50	  }
51	
52	  const now = new Date().toISOString();
53	  const fileId = crypto.randomUUID();
54	
55	  const fileRecord: FileRecord = {
56	    id: fileId,
57	    name: fileName,
58	    mimeType,
59	    size: fileSize,
60	    sha256,
61	    currentVersionId: '',
62	    createdBy,
63	    isDeleted: false,
64	    createdAt: now,
65	    updatedAt: now,
66	    version: 1,
67	  };
68	
69	  await fileRepo.add(fileRecord);
70	
71	  // Create transfer session
72	  const totalChunks = Math.ceil(fileSize / FILE_CHUNK_SIZE);
73	  const session = await createTransferSession(fileId, fileSize, totalChunks);
74	
75	  logger.info('File ingestion started', { fileId, fileName, totalChunks, sha256 });
76	  return { file: fileRecord, session, deduplicated: false };
77	}
78	
79	export async function createTransferSession(
80	  fileId: string,
81	  fileSize: number,
82	  totalChunks?: number,
83	): Promise<TransferSession> {
84	  const chunks = totalChunks ?? Math.ceil(fileSize / FILE_CHUNK_SIZE);
85	  const now = new Date().toISOString();
86	
87	  const session: TransferSession = {
88	    id: crypto.randomUUID(),
89	    fileId,
90	    status: TransferState.Pending,
91	    totalChunks: chunks,
92	    completedChunks: 0,
93	    chunkSize: FILE_CHUNK_SIZE,
94	    startedAt: now,
95	    createdAt: now,
96	    updatedAt: now,
97	    version: 1,
98	  };
99	
100	  await transferRepo.add(session);
101	  return session;
102	}
103	
104	export async function pauseTransfer(sessionId: string): Promise<TransferSession> {
105	  const session = await transferRepo.getById(sessionId);
106	  if (!session) throw new ValidationServiceError('Session not found', [
107	    { field: 'sessionId', message: 'Transfer session not found', code: 'not_found' },
108	  ]);
109	
110	  if (session.status !== TransferState.Active) {
111	    throw new ValidationServiceError('Cannot pause non-active transfer', [
112	      { field: 'status', message: `Transfer is ${session.status}`, code: 'invalid_state' },
113	    ]);
114	  }
115	
116	  return transferRepo.put({
117	    ...session,
118	    status: TransferState.Paused,
119	    updatedAt: new Date().toISOString(),
120	  });
121	}
122	
123	export async function resumeTransfer(sessionId: string): Promise<TransferSession> {
124	  const session = await transferRepo.getById(sessionId);
125	  if (!session) throw new ValidationServiceError('Session not found', [
126	    { field: 'sessionId', message: 'Transfer session not found', code: 'not_found' },
127	  ]);
128	
129	  if (session.status !== TransferState.Paused) {
130	    throw new ValidationServiceError('Cannot resume non-paused transfer', [
131	      { field: 'status', message: `Transfer is ${session.status}`, code: 'invalid_state' },
132	    ]);
133	  }
134	
135	  return transferRepo.put({
136	    ...session,
137	    status: TransferState.Active,
138	    updatedAt: new Date().toISOString(),
139	  });
140	}
141	
142	export async function completeTransfer(sessionId: string): Promise<TransferSession> {
143	  const session = await transferRepo.getById(sessionId);
144	  if (!session) throw new ValidationServiceError('Session not found', [
145	    { field: 'sessionId', message: 'Transfer session not found', code: 'not_found' },
146	  ]);
147	
148	  if (session.completedChunks < session.totalChunks) {
149	    throw new ValidationServiceError('Transfer incomplete', [
150	      {
151	        field: 'chunks',
152	        message: `${session.completedChunks}/${session.totalChunks} chunks completed`,
153	        code: 'incomplete',
154	      },
155	    ]);
156	  }
157	
158	  return transferRepo.put({
159	    ...session,
160	    status: TransferState.Completed,
161	    updatedAt: new Date().toISOString(),
162	  });
163	}
164	
165	export async function getFile(fileId: string): Promise<FileRecord | undefined> {
166	  return fileRepo.getById(fileId);
167	}
168	
169	export async function getFiles(): Promise<FileRecord[]> {
170	  return fileRepo.getAll();
171	}
172	
173	export async function getTransferSession(sessionId: string): Promise<TransferSession | undefined> {
174	  return transferRepo.getById(sessionId);
175	}
