13	export class ChunkScheduler {
14	  private activeCount = 0;
15	  private bandwidthCap: number = DEFAULT_BANDWIDTH_CAP;
16	  private isPaused = false;
17	  private lastChunkTime = 0;
18	
19	  setBandwidthCap(bytesPerSecond: number): void {
20	    if (bytesPerSecond <= 0) {
21	      throw new ValidationServiceError('Invalid bandwidth cap', [
22	        { field: 'bandwidthCap', message: 'Must be greater than 0', code: 'invalid_bandwidth' },
23	      ]);
24	    }
25	    this.bandwidthCap = bytesPerSecond;
26	  }
27	
28	  getBandwidthCap(): number {
29	    return this.bandwidthCap;
30	  }
31	
32	  getActiveCount(): number {
33	    return this.activeCount;
34	  }
35	
36	  async scheduleChunks(
37	    sessionId: string,
38	    fileData: ArrayBuffer,
39	    onProgress?: (completed: number, total: number) => void,
40	  ): Promise<void> {
41	    const session = await transferRepo.getById(sessionId);
42	    if (!session) throw new ValidationServiceError('Session not found', [
43	      { field: 'sessionId', message: 'Not found', code: 'not_found' },
44	    ]);
45	
46	    // Set session to active
47	    await transferRepo.put({
48	      ...session,
49	      status: TransferState.Active,
50	      updatedAt: new Date().toISOString(),
51	    });
52	
53	    const totalChunks = session.totalChunks;
54	    const existingChunks = await chunkRepo.getByFile(session.fileId);
55	    const completedIndices = new Set(existingChunks.map(c => c.chunkIndex));
56	
57	    const pendingIndices: number[] = [];
58	    for (let i = 0; i < totalChunks; i++) {
59	      if (!completedIndices.has(i)) {
60	        pendingIndices.push(i);
61	      }
62	    }
63	
64	    // Process chunks with concurrency limit
65	    let completed = existingChunks.length;
66	
67	    const processNext = async (index: number): Promise<void> => {
68	      if (this.isPaused) return;
69	
70	      // Throttle based on bandwidth cap
71	      await this.throttle();
72	
73	      this.activeCount++;
74	      try {
75	        const start = index * FILE_CHUNK_SIZE;
76	        const end = Math.min(start + FILE_CHUNK_SIZE, fileData.byteLength);
77	        const chunkData = fileData.slice(start, end);
78	
79	        const isFinal = index === totalChunks - 1;
80	        const sizeValidation = validateChunkSize(chunkData.byteLength, isFinal);
81	        if (!sizeValidation.valid) {
82	          throw new ValidationServiceError('Invalid chunk', sizeValidation.errors);
83	        }
84	
85	        await this.processChunk(session.fileId, index, chunkData);
86	        completed++;
87	
88	        // Update session progress
89	        const currentSession = await transferRepo.getById(sessionId);
90	        if (currentSession) {
91	          await transferRepo.put({
92	            ...currentSession,
93	            completedChunks: completed,
94	            updatedAt: new Date().toISOString(),
95	          });
96	        }
97	
98	        onProgress?.(completed, totalChunks);
99	      } finally {
100	        this.activeCount--;
101	      }
102	    };
103	
104	    // Promise pool: process up to MAX_CONCURRENT_CHUNKS at a time
105	    const pool: Promise<void>[] = [];
106	    for (const index of pendingIndices) {
107	      if (this.isPaused) break;
108	
109	      const promise = processNext(index);
110	      pool.push(promise);
111	
112	      if (pool.length >= MAX_CONCURRENT_CHUNKS) {
113	        await Promise.race(pool);
114	        // Remove completed promises
115	        for (let i = pool.length - 1; i >= 0; i--) {
116	          const settled = await Promise.race([
117	            pool[i].then(() => true),
118	            Promise.resolve(false),
119	          ]);
120	          if (settled) pool.splice(i, 1);
121	        }
122	      }
123	    }
124	
125	    // Wait for remaining
126	    await Promise.all(pool);
127	
128	    logger.info('Chunk scheduling complete', { sessionId, completed, totalChunks });
129	  }
130	
131	  async processChunk(
132	    fileId: string,
133	    chunkIndex: number,
134	    data: ArrayBuffer,
135	  ): Promise<FileChunk> {
136	    const now = new Date().toISOString();
137	    const chunk: FileChunk = {
138	      id: crypto.randomUUID(),
139	      fileId,
140	      chunkIndex,
141	      data,
142	      size: data.byteLength,
143	      createdAt: now,
144	      updatedAt: now,
145	      version: 1,
146	    };
147	
148	    await chunkRepo.add(chunk);
149	    return chunk;
150	  }
