24	  '/': { label: 'Login', icon: 'login', showInNav: false },
25	  '/dashboard': { label: 'Dashboard', icon: 'dashboard', showInNav: true },
26	  '/inventory': { label: 'Inventory', icon: 'inventory', showInNav: true },
27	  '/inventory/ledger': { label: 'Ledger', icon: 'ledger', showInNav: false },
28	  '/orders': { label: 'Orders', icon: 'orders', showInNav: true },
29	  '/orders/waves': { label: 'Waves', icon: 'waves', showInNav: false },
30	  '/files': { label: 'Files', icon: 'files', showInNav: true },
