1	<script lang="ts">
2	  import { getContext } from 'svelte';
3	  import Drawer from '$components/Drawer.svelte';
4	  import {
5	    reportDiscrepancy,
6	    reviewDiscrepancy,
7	    verifyDiscrepancy,
8	    resolveDiscrepancy,
9	    getDiscrepanciesByTask,
10	  } from '$modules/orders';
11	  import { DiscrepancyState } from '$lib/types/enums';
12	  import type { Discrepancy, DiscrepancyAttachment } from '$lib/types/orders';
13	  import { getCurrentSession } from '$lib/security/auth.service';
14	
15	  export let open = false;
16	  export let taskId = '';
17	
18	  const toast: any = getContext('toast');
19	
20	  let discrepancies: Discrepancy[] = [];
21	  let description = '';
22	  let verificationNotes = '';
23	  let error = '';
24	  let reportFiles: FileList | null = null;
25	  let verifyFiles: FileList | null = null;
26	  let reportFileInput: HTMLInputElement;
27	  let verifyFileInput: HTMLInputElement;
28	
29	  function filesToAttachments(files: FileList | null, discrepancyId: string): DiscrepancyAttachment[] {
30	    if (!files) return [];
31	    return Array.from(files).map(f => ({
32	      id: crypto.randomUUID(),
33	      discrepancyId,
34	      fileId: crypto.randomUUID(),
35	      type: f.type || 'application/octet-stream',
36	      name: f.name,
37	      addedAt: new Date().toISOString(),
38	    }));
39	  }
40	
41	  $: if (open && taskId) loadDiscrepancies();
42	
43	  async function loadDiscrepancies() {
44	    discrepancies = await getDiscrepanciesByTask(taskId);
45	  }
46	
47	  async function handleReport() {
48	    error = '';
49	    try {
50	      const attachments = filesToAttachments(reportFiles, '');
51	      await reportDiscrepancy(taskId, getCurrentSession()?.userId ?? 'unknown', description, attachments);
52	      description = '';
53	      reportFiles = null;
54	      if (reportFileInput) reportFileInput.value = '';
55	      await loadDiscrepancies();
56	      toast?.addToast('Discrepancy reported', 'warning');
57	    } catch (e: any) { error = e.message; }
58	  }
59	
60	  async function handleReview(id: string) {
61	    try {
62	      await reviewDiscrepancy(id);
63	      await loadDiscrepancies();
64	    } catch (e: any) { error = e.message; }
65	  }
66	
67	  async function handleVerify(id: string) {
68	    error = '';
69	    try {
70	      const attachments = filesToAttachments(verifyFiles, id);
71	      await verifyDiscrepancy(id, getCurrentSession()?.userId ?? 'unknown', verificationNotes || 'Verified', attachments);
72	      verificationNotes = '';
73	      verifyFiles = null;
74	      if (verifyFileInput) verifyFileInput.value = '';
75	      await loadDiscrepancies();
76	      toast?.addToast('Discrepancy verified', 'success');
77	    } catch (e: any) { error = e.message; }
78	  }
79	
80	  async function handleResolve(id: string) {
81	    try {
82	      await resolveDiscrepancy(id);
83	      await loadDiscrepancies();
84	      toast?.addToast('Discrepancy resolved', 'success');
85	    } catch (e: any) { error = e.message; }
86	  }
87	
88	  function stateLabel(state: DiscrepancyState): string {
89	    return state.replace('_', ' ').replace(/\b\w/g, c => c.toUpperCase());
90	  }
91	</script>
92	
93	<Drawer {open} title="Discrepancies — Task {taskId}" on:close={() => { open = false; }}>
94	  {#if error}<div class="form-error">{error}</div>{/if}
95	
96	  <div class="report-form">
97	    <h4>Report New</h4>
98	    <div class="report-row">
99	      <input type="text" placeholder="Description" bind:value={description} />
100	      <button on:click={handleReport} disabled={!description.trim()}>Report</button>
101	    </div>
102	    <input type="file" multiple bind:this={reportFileInput}
103	           on:change={(e) => { reportFiles = e.target.files; }} />
104	    {#if reportFiles && reportFiles.length > 0}
105	      <div class="file-list">
106	        {#each Array.from(reportFiles) as f}
107	          <span class="file-chip">{f.name}</span>
108	        {/each}
109	      </div>
110	    {/if}
111	  </div>
112	
113	  <div class="discrepancy-list">
114	    {#each discrepancies as d}
115	      <div class="disc-card">
116	        <div class="disc-header">
117	          <span class="disc-state" data-state={d.state}>{stateLabel(d.state)}</span>
118	          <span class="disc-date">{new Date(d.reportedAt).toLocaleString()}</span>
119	        </div>
120	        <p class="disc-desc">{d.description}</p>
121	        {#if d.verificationNotes}<p class="disc-notes">Verification: {d.verificationNotes}</p>{/if}
122	        {#if d.attachments && d.attachments.length > 0}
123	          <div class="attachment-list">
124	            <span class="attachment-label">Attachments:</span>
125	            {#each d.attachments as att}
126	              <span class="attachment-chip">{att.name}</span>
127	            {/each}
128	          </div>
129	        {/if}
130	        <div class="disc-actions">
131	          {#if d.state === DiscrepancyState.Opened}
132	            <button on:click={() => handleReview(d.id)}>Review</button>
133	          {/if}
134	          {#if d.state === DiscrepancyState.UnderReview}
135	            <input type="text" placeholder="Verification notes" bind:value={verificationNotes} />
136	            <input type="file" multiple bind:this={verifyFileInput}
137	                   on:change={(e) => { verifyFiles = e.target.files; }} />
138	            <button on:click={() => handleVerify(d.id)}>Verify</button>
139	          {/if}
140	          {#if d.state === DiscrepancyState.Verified}
141	            <button on:click={() => handleResolve(d.id)}>Resolve</button>
142	          {/if}
143	        </div>
144	      </div>
145	    {/each}
146	    {#if discrepancies.length === 0}
147	      <p class="empty">No discrepancies for this task</p>
148	    {/if}
149	  </div>
150	</Drawer>
151	
152	<style>
153	  .report-form { display: flex; flex-direction: column; gap: var(--spacing-xs); margin-bottom: var(--spacing-md); }
154	  .report-row { display: flex; gap: var(--spacing-xs); }
155	  .report-row input[type="text"] { flex: 1; padding: var(--spacing-xs); border: 1px solid var(--color-border); border-radius: var(--radius-sm); }
156	  .report-form button { padding: var(--spacing-xs) var(--spacing-sm); background: var(--color-warning); color: white; border: none; border-radius: var(--radius-sm); cursor: pointer; }
157	  .report-form input[type="file"] { font-size: 0.8rem; }
158	  .file-list { display: flex; flex-wrap: wrap; gap: 4px; }
159	  .file-chip { font-size: 0.75rem; padding: 2px 6px; background: #eff6ff; border-radius: var(--radius-sm); color: var(--color-primary); }
160	  .attachment-list { margin-top: var(--spacing-xs); display: flex; flex-wrap: wrap; gap: 4px; align-items: center; }
161	  .attachment-label { font-size: 0.75rem; font-weight: 600; color: var(--color-muted); }
162	  .attachment-chip { font-size: 0.75rem; padding: 2px 6px; background: #f3f4f6; border-radius: var(--radius-sm); }
163	  h4 { font-size: 0.85rem; margin-bottom: var(--spacing-xs); }
164	  .disc-card { border: 1px solid var(--color-border); border-radius: var(--radius-sm); padding: var(--spacing-sm); margin-bottom: var(--spacing-sm); }
165	  .disc-header { display: flex; justify-content: space-between; align-items: center; margin-bottom: var(--spacing-xs); }
166	  .disc-state { font-size: 0.75rem; padding: 2px 8px; border-radius: 9999px; font-weight: 600; background: #e5e7eb; }
167	  .disc-date { font-size: 0.75rem; color: var(--color-muted); }
