1	import type { Writable } from 'svelte/store';
2	import { get } from 'svelte/store';
3	
4	export interface OptimisticUpdate<T> {
5	  previous: T;
6	  pending: T;
7	  rollback: () => void;
8	}
9	
10	export async function createOptimisticUpdate<T>(
11	  store: Writable<T>,
12	  newValue: T,
13	  persistFn: () => Promise<void>,
14	): Promise<OptimisticUpdate<T>> {
15	  const previous = get(store);
16	  store.set(newValue);
17	
18	  try {
19	    await persistFn();
20	    return {
21	      previous,
22	      pending: newValue,
23	      rollback: () => store.set(previous),
24	    };
25	  } catch (error) {
26	    store.set(previous);
27	    throw error;
28	  }
29	}
