31	async function writeLedgerEntry(
32	  entry: Omit<MovementEntry, 'id' | 'createdAt' | 'updatedAt' | 'version'>,
33	): Promise<MovementEntry> {
34	  const now = new Date().toISOString();
35	  const ledgerEntry: MovementEntry = {
36	    ...entry,
37	    id: crypto.randomUUID(),
38	    createdAt: now,
39	    updatedAt: now,
40	    version: 1,
41	  };
42	  await ledgerRepo.add(ledgerEntry);
43	  return ledgerEntry;
44	}
