46	export async function createOrder(
47	  orderData: Partial<Order> & { lines: OrderLine[] },
48	): Promise<{ order: Order; reservations: Reservation[] }> {
49	  const operatorId = requireOperatorId();
50	
51	  const validation = validateOrder(orderData);
52	  if (!validation.valid) throw new ValidationServiceError('Invalid order', validation.errors);
53	
54	  const now = new Date().toISOString();
55	  const order: Order = {
56	    id: crypto.randomUUID(),
57	    orderNumber: orderData.orderNumber ?? `ORD-${Date.now()}`,
58	    status: OrderStatus.Confirmed,
59	    lines: orderData.lines,
60	    customerId: orderData.customerId,
61	    notes: orderData.notes,
62	    createdBy: operatorId,
63	    createdAt: now,
64	    updatedAt: now,
65	    version: 1,
66	  };
67	
68	  // Phase 1: Pre-flight validation — check ALL lines before any mutation
69	  const lineChecks: Array<{ line: OrderLine; stockRecord: any }> = [];
70	  for (const line of order.lines) {
71	    if (!line.binId) continue;
72	
73	    const stockRecords = await stockRepo.getByIndex('binId', line.binId);
74	    const stockRecord = stockRecords.find((r: any) => r.skuId === line.skuId);
75	
76	    if (!stockRecord || stockRecord.quantity < line.quantity) {
77	      throw new ValidationServiceError('Insufficient stock for reservation', [
78	        {
79	          field: `line.${line.skuId}`,
80	          message: `Available: ${stockRecord?.quantity ?? 0}, requested: ${line.quantity}`,
81	          code: 'insufficient_stock',
82	        },
83	      ]);
84	    }
85	    lineChecks.push({ line, stockRecord });
86	  }
87	
88	  // Phase 2: All validated — now perform mutations (no throw possible from stock checks)
89	  const reservations: Reservation[] = [];
90	
91	  for (const { line, stockRecord } of lineChecks) {
92	    await stockRepo.put({
93	      ...stockRecord,
94	      quantity: stockRecord.quantity - line.quantity,
95	      updatedAt: now,
96	    });
97	
98	    const reservation: Reservation = {
99	      id: crypto.randomUUID(),
100	      orderId: order.id,
101	      skuId: line.skuId,
102	      binId: line.binId!,
103	      quantity: line.quantity,
104	      status: ReservationStatus.Active,
105	      lastActivityAt: now,
106	      createdAt: now,
107	      updatedAt: now,
108	      version: 1,
109	    };
110	    await reservationRepo.add(reservation);
111	    reservations.push(reservation);
112	
113	    await writeLedgerEntry({
114	      timestamp: now,
115	      operatorId,
116	      sourceBinId: line.binId!,
117	      destinationBinId: null,
118	      skuId: line.skuId,
119	      quantity: line.quantity,
120	      reasonCode: MovementReason.ReservationHold,
121	      orderId: order.id,
122	    });
123	
124	    line.reservationId = reservation.id;
125	  }
126	
127	  order.status = OrderStatus.Reserved;
128	  await orderRepo.add(order);
129	
130	  logger.info('Order created with reservations', {
131	    orderId: order.id,
132	    lineCount: order.lines.length,
133	    reservationCount: reservations.length,
134	  });
135	
136	  return { order, reservations };
137	}
