171	export async function releaseReservation(
172	  reservationId: string,
173	  reason: ReleaseReason,
174	  operatorId?: string,
175	): Promise<Reservation> {
176	  const opId = operatorId ?? requireOperatorId();
177	
178	  const reservation = await reservationRepo.getById(reservationId);
179	  if (!reservation) throw new ValidationServiceError('Reservation not found', [
180	    { field: 'reservationId', message: 'Reservation does not exist', code: 'not_found' },
181	  ]);
182	
183	  const now = new Date().toISOString();
184	
