186	  const stockRecords = await stockRepo.getByIndex('binId', reservation.binId);
187	  const stockRecord = stockRecords.find(r => r.skuId === reservation.skuId);
188	  if (stockRecord) {
189	    await stockRepo.put({
190	      ...stockRecord,
191	      quantity: stockRecord.quantity + reservation.quantity,
192	      updatedAt: now,
193	    });
194	  }
195	
196	  // Write release ledger entry
197	  await writeLedgerEntry({
198	    timestamp: now,
199	    operatorId: opId,
200	    sourceBinId: null,
201	    destinationBinId: reservation.binId,
202	    skuId: reservation.skuId,
203	    quantity: reservation.quantity,
204	    reasonCode: MovementReason.ReservationRelease,
205	    orderId: reservation.orderId,
206	  });
207	
208	  const released = await reservationRepo.put({
209	    ...reservation,
210	    status: ReservationStatus.Released,
211	    releasedAt: now,
212	    releaseReason: reason,
213	    updatedAt: now,
214	  });
215	
216	  return released;
217	}
