157	export async function transferStock(
158	  fromBinId: string,
159	  toBinId: string,
160	  skuId: string,
161	  quantity: number,
162	  fromWarehouseId: string,
163	  toWarehouseId: string,
164	  notes?: string,
165	): Promise<{ ledgerEntries: MovementEntry[]; alerts: SafetyStockAlert[] }> {
166	  const operatorId = requireOperatorId();
167	
168	  const validation = validateTransfer(fromBinId, toBinId, skuId, quantity);
169	  if (!validation.valid) throw new ValidationServiceError('Invalid transfer', validation.errors);
170	
171	  const sourceRecord = await getOrCreateStockRecord(fromBinId, skuId, fromWarehouseId);
172	  if (sourceRecord.quantity < quantity) {
173	    throw new ValidationServiceError('Insufficient stock for transfer', [
174	      { field: 'quantity', message: `Available: ${sourceRecord.quantity}, requested: ${quantity}`, code: 'insufficient_stock' },
175	    ]);
176	  }
177	
178	  await stockRepo.put({
179	    ...sourceRecord,
180	    quantity: sourceRecord.quantity - quantity,
181	    updatedAt: new Date().toISOString(),
182	  });
183	
184	  const destRecord = await getOrCreateStockRecord(toBinId, skuId, toWarehouseId);
185	  await stockRepo.put({
186	    ...destRecord,
187	    quantity: destRecord.quantity + quantity,
188	    updatedAt: new Date().toISOString(),
189	  });
190	
191	  const now = new Date().toISOString();
192	  const outEntry = await writeLedgerEntry({
193	    timestamp: now, operatorId, sourceBinId: fromBinId, destinationBinId: null,
194	    skuId, quantity, reasonCode: MovementReason.TransferOut, notes,
195	  });
196	  const inEntry = await writeLedgerEntry({
197	    timestamp: now, operatorId, sourceBinId: null, destinationBinId: toBinId,
198	    skuId, quantity, reasonCode: MovementReason.TransferIn, notes,
199	  });
200	
201	  logger.info('Stock transferred', { fromBinId, toBinId, skuId, quantity });
202	  const alerts = [
203	    ...await checkSafetyStock(fromWarehouseId),
204	    ...(fromWarehouseId !== toWarehouseId ? await checkSafetyStock(toWarehouseId) : []),
205	  ];
206	  return { ledgerEntries: [outEntry, inEntry], alerts };
207	}
