209	export async function cycleCount(
210	  binId: string,
211	  skuId: string,
212	  warehouseId: string,
213	  actualQty: number,
214	  notes?: string,
215	): Promise<{ stockRecord: StockRecord; ledgerEntry: MovementEntry | null; alerts: SafetyStockAlert[] }> {
216	  const operatorId = requireOperatorId();
217	
218	  const validation = validateCycleCount(binId, skuId, actualQty);
219	  if (!validation.valid) throw new ValidationServiceError('Invalid cycle count', validation.errors);
220	
221	  const record = await getOrCreateStockRecord(binId, skuId, warehouseId);
222	  const diff = actualQty - record.quantity;
223	
224	  const updated = await stockRepo.put({
225	    ...record,
226	    quantity: actualQty,
227	    lastCountedAt: new Date().toISOString(),
228	    updatedAt: new Date().toISOString(),
229	  });
230	
231	  let ledgerEntry: MovementEntry | null = null;
232	  if (diff !== 0) {
233	    ledgerEntry = await writeLedgerEntry({
234	      timestamp: new Date().toISOString(),
235	      operatorId,
236	      sourceBinId: diff < 0 ? binId : null,
237	      destinationBinId: diff > 0 ? binId : null,
238	      skuId,
239	      quantity: Math.abs(diff),
240	      reasonCode: MovementReason.CycleCountAdjust,
241	      notes: notes ?? `Cycle count adjustment: ${record.quantity} → ${actualQty}`,
242	    });
243	  }
244	
245	  logger.info('Cycle count', { binId, skuId, previousQty: record.quantity, actualQty });
246	  const alerts = await checkSafetyStock(warehouseId);
247	  return { stockRecord: updated, ledgerEntry, alerts };
248	}
