250	export async function checkSafetyStock(warehouseId?: string): Promise<SafetyStockAlert[]> {
251	  const alerts: SafetyStockAlert[] = [];
252	
253	  // Get all stock records in scope
254	  const stockRecords = warehouseId
255	    ? await stockRepo.getByWarehouse(warehouseId)
256	    : await stockRepo.getAll();
257	
258	  // Build unique warehouse+SKU pairs from actual stock
259	  const pairs = new Map<string, { warehouseId: string; skuId: string; totalStock: number }>();
260	  for (const r of stockRecords) {
261	    const key = `${r.warehouseId}:${r.skuId}`;
262	    const existing = pairs.get(key);
263	    if (existing) {
264	      existing.totalStock += r.quantity;
265	    } else {
266	      pairs.set(key, { warehouseId: r.warehouseId, skuId: r.skuId, totalStock: r.quantity });
267	    }
268	  }
269	
270	  // Get explicit configs
271	  const configs = warehouseId
272	    ? await safetyStockRepo.getByWarehouse(warehouseId)
273	    : await safetyStockRepo.getAll();
274	
275	  const configMap = new Map<string, number>();
276	  for (const c of configs) {
277	    configMap.set(`${c.warehouseId}:${c.skuId}`, c.threshold);
278	  }
279	
280	  // Check each warehouse+SKU pair against configured or default threshold
281	  for (const [key, pair] of pairs) {
282	    const threshold = configMap.get(key) ?? SAFETY_STOCK_DEFAULT;
283	    if (pair.totalStock < threshold) {
284	      alerts.push({
285	        warehouseId: pair.warehouseId,
286	        skuId: pair.skuId,
287	        currentStock: pair.totalStock,
288	        threshold,
289	        triggeredAt: new Date().toISOString(),
290	      });
291	    }
292	  }
293	
294	  if (alerts.length > 0) {
295	    logger.warn('Safety stock alerts', { count: alerts.length, warehouseId });
296	    // Trigger low-stock notifications
297	    const session = getCurrentSession();
298	    for (const alert of alerts) {
299	      try {
300	        await dispatchNotification(
301	          session?.userId ?? 'system',
302	          NotificationType.LowStock,
303	          'Low Stock Alert',
304	          `SKU ${alert.skuId} in warehouse ${alert.warehouseId}: ${alert.currentStock}/${alert.threshold} units`,
305	          { skuId: alert.skuId, warehouseId: alert.warehouseId, currentStock: alert.currentStock, threshold: alert.threshold },
306	        );
307	      } catch { /* notification failure should not block inventory operation */ }
308	    }
309	  }
310	  return alerts;
311	}
