1	import { OrderRepository, ReservationRepository } from '$lib/db';
2	import { StockRecordRepository, MovementLedgerRepository } from '$lib/db';
3	import { validateOrder, validateReservation } from '$lib/validators';
4	import { ValidationServiceError } from '$lib/services/errors';
5	import { getCurrentSession } from '$lib/security/auth.service';
6	import { createLogger } from '$lib/logging';
7	import { getExpiredReservations } from './reservation-timer';
8	import {
9	  OrderStatus,
10	  ReservationStatus,
11	  ReleaseReason,
12	  MovementReason,
13	} from '$lib/types/enums';
14	import type { Order, OrderLine, Reservation } from '$lib/types/orders';
15	import type { MovementEntry } from '$lib/types/inventory';
16	
17	const orderRepo = new OrderRepository();
18	const reservationRepo = new ReservationRepository();
19	const stockRepo = new StockRecordRepository();
20	const ledgerRepo = new MovementLedgerRepository();
21	const logger = createLogger('inventory');
22	
23	function requireOperatorId(): string {
24	  const session = getCurrentSession();
25	  if (!session) throw new ValidationServiceError('Not authenticated', [
26	    { field: 'session', message: 'User must be logged in', code: 'unauthenticated' },
27	  ]);
28	  return session.userId;
29	}
