139	export async function cancelOrder(orderId: string): Promise<{
140	  order: Order;
141	  releasedReservations: Reservation[];
142	}> {
143	  const operatorId = requireOperatorId();
144	
145	  const order = await orderRepo.getById(orderId);
146	  if (!order) throw new ValidationServiceError('Order not found', [
147	    { field: 'orderId', message: 'Order does not exist', code: 'not_found' },
148	  ]);
149	
150	  const activeReservations = await reservationRepo.getByOrder(orderId);
151	  const toRelease = activeReservations.filter(r => r.status === ReservationStatus.Active);
152	
153	  const now = new Date().toISOString();
154	  const releasedReservations: Reservation[] = [];
155	
156	  for (const reservation of toRelease) {
157	    const released = await releaseReservation(reservation.id, ReleaseReason.Cancel, operatorId);
158	    releasedReservations.push(released);
159	  }
160	
161	  const updatedOrder = await orderRepo.put({
162	    ...order,
163	    status: OrderStatus.Cancelled,
164	    updatedAt: now,
165	  });
166	
167	  logger.info('Order cancelled', { orderId, releasedCount: releasedReservations.length });
168	  return { order: updatedOrder, releasedReservations };
169	}
170	
171	export async function releaseReservation(
172	  reservationId: string,
173	  reason: ReleaseReason,
174	  operatorId?: string,
175	): Promise<Reservation> {
176	  const opId = operatorId ?? requireOperatorId();
177	
178	  const reservation = await reservationRepo.getById(reservationId);
179	  if (!reservation) throw new ValidationServiceError('Reservation not found', [
180	    { field: 'reservationId', message: 'Reservation does not exist', code: 'not_found' },
181	  ]);
182	
183	  const now = new Date().toISOString();
184	
185	  // Return stock
186	  const stockRecords = await stockRepo.getByIndex('binId', reservation.binId);
187	  const stockRecord = stockRecords.find(r => r.skuId === reservation.skuId);
188	  if (stockRecord) {
189	    await stockRepo.put({
190	      ...stockRecord,
191	      quantity: stockRecord.quantity + reservation.quantity,
192	      updatedAt: now,
193	    });
194	  }
195	
196	  // Write release ledger entry
197	  await writeLedgerEntry({
198	    timestamp: now,
199	    operatorId: opId,
200	    sourceBinId: null,
201	    destinationBinId: reservation.binId,
202	    skuId: reservation.skuId,
203	    quantity: reservation.quantity,
204	    reasonCode: MovementReason.ReservationRelease,
205	    orderId: reservation.orderId,
206	  });
207	
208	  const released = await reservationRepo.put({
209	    ...reservation,
210	    status: ReservationStatus.Released,
211	    releasedAt: now,
212	    releaseReason: reason,
213	    updatedAt: now,
214	  });
215	
216	  return released;
217	}
218	
219	export async function releaseExpiredReservations(
220	  now: Date = new Date(),
221	): Promise<Reservation[]> {
222	  const allActive = await reservationRepo.getActive();
223	  const expired = getExpiredReservations(allActive, now);
224	
225	  const released: Reservation[] = [];
226	  for (const reservation of expired) {
227	    const r = await releaseReservation(reservation.id, ReleaseReason.Timeout);
228	    released.push(r);
229	  }
230	
231	  if (released.length > 0) {
232	    logger.info('Released expired reservations', { count: released.length });
233	  }
234	  return released;
235	}
