237	export async function updateOrderActivity(orderId: string): Promise<void> {
238	  const reservations = await reservationRepo.getByOrder(orderId);
239	  const now = new Date().toISOString();
240	
241	  for (const r of reservations) {
242	    if (r.status === ReservationStatus.Active) {
243	      await reservationRepo.put({ ...r, lastActivityAt: now, updatedAt: now });
244	    }
245	  }
246	}
