248	export async function getOrder(orderId: string): Promise<Order | undefined> {
249	  return orderRepo.getById(orderId);
250	}
251	
252	export async function getOrders(): Promise<Order[]> {
253	  return orderRepo.getAll();
254	}
255	
256	export async function getReservationsByOrder(orderId: string): Promise<Reservation[]> {
257	  return reservationRepo.getByOrder(orderId);
258	}
