1	import type { Reservation } from '$lib/types/orders';
2	import { ReservationStatus } from '$lib/types/enums';
3	import { RESERVATION_TIMEOUT_MS } from '$lib/constants';
4	
5	export function isReservationExpired(
6	  lastActivityAt: string,
7	  now: Date = new Date(),
8	): boolean {
9	  return now.getTime() - new Date(lastActivityAt).getTime() > RESERVATION_TIMEOUT_MS;
10	}
11	
12	export function getExpiredReservations(
13	  reservations: Reservation[],
14	  now: Date = new Date(),
15	): Reservation[] {
16	  return reservations.filter(
17	    r => r.status === ReservationStatus.Active && isReservationExpired(r.lastActivityAt, now),
18	  );
19	}
20	
21	export function getExpiresAt(lastActivityAt: string): Date {
22	  return new Date(new Date(lastActivityAt).getTime() + RESERVATION_TIMEOUT_MS);
23	}
