30	export async function ingestFile(
31	  fileName: string,
32	  fileSize: number,
33	  mimeType: string,
34	  fileData: ArrayBuffer,
35	  createdBy: string,
36	): Promise<{ file: FileRecord; session: TransferSession | null; deduplicated: boolean }> {
37	  const validation = validateFileIngest({ name: fileName, size: fileSize, type: mimeType });
38	  if (!validation.valid) throw new ValidationServiceError('Invalid file', validation.errors);
39	
40	  const sha256 = await computeHash(fileData);
41	
42	  // Check deduplication
43	  const dedup = await checkDedup(sha256);
44	  if (dedup.exists && dedup.fileId) {
45	    const existingFile = await fileRepo.getById(dedup.fileId);
46	    if (existingFile) {
47	      logger.info('File deduplicated', { fileName, sha256 });
48	      return { file: existingFile, session: null, deduplicated: true };
49	    }
50	  }
51	
52	  const now = new Date().toISOString();
53	  const fileId = crypto.randomUUID();
54	
55	  const fileRecord: FileRecord = {
56	    id: fileId,
57	    name: fileName,
58	    mimeType,
59	    size: fileSize,
60	    sha256,
61	    currentVersionId: '',
62	    createdBy,
63	    isDeleted: false,
64	    createdAt: now,
65	    updatedAt: now,
66	    version: 1,
67	  };
68	
69	  await fileRepo.add(fileRecord);
70	
71	  // Create transfer session
72	  const totalChunks = Math.ceil(fileSize / FILE_CHUNK_SIZE);
73	  const session = await createTransferSession(fileId, fileSize, totalChunks);
74	
75	  logger.info('File ingestion started', { fileId, fileName, totalChunks, sha256 });
76	  return { file: fileRecord, session, deduplicated: false };
77	}
