17	export async function enrollProfile(
18	  name: string,
19	  groupId?: string,
20	  attributes: Record<string, string> = {},
21	): Promise<FaceProfile> {
22	  const dek = getCurrentDEK();
23	
24	  let encryptedAttributes: string | undefined;
25	  let attributesIV: string | undefined;
26	
27	  if (dek) {
28	    const json = JSON.stringify(attributes);
29	    const { ciphertext, iv } = await encrypt(json, dek);
30	    encryptedAttributes = arrayBufferToBase64(ciphertext);
31	    attributesIV = uint8ArrayToBase64(iv);
32	  }
33	
34	  const now = new Date().toISOString();
35	  const profile: FaceProfile = {
36	    id: crypto.randomUUID(),
37	    name,
38	    groupId,
39	    attributes: dek ? {} : attributes,
40	    encryptedAttributes,
41	    attributesIV,
42	    enrolledBy: 'current-user',
43	    enrolledAt: now,
44	    createdAt: now,
45	    updatedAt: now,
46	    version: 1,
47	  };
48	  await profileRepo.add(profile);
49	  logger.info('Profile enrolled', { profileId: profile.id, name });
50	  return { ...profile, attributes };
51	}
