83	export async function decryptProfileAttributes(
84	  profile: FaceProfile,
85	): Promise<Record<string, string>> {
86	  if (!profile.encryptedAttributes || !profile.attributesIV) {
87	    return profile.attributes;
88	  }
89	
90	  const dek = getCurrentDEK();
91	  if (!dek) return {};
92	
93	  try {
94	    const ciphertextBytes = base64ToUint8Array(profile.encryptedAttributes);
95	    const ivBytes = base64ToUint8Array(profile.attributesIV);
96	    // Use Uint8Array directly as BufferSource (avoids ArrayBuffer type issues in Node.js)
97	    const plaintext = await globalThis.crypto.subtle.decrypt(
98	      { name: 'AES-GCM', iv: ivBytes },
99	      dek,
100	      ciphertextBytes,
101	    );
102	    const json = new TextDecoder().decode(plaintext);
103	    return JSON.parse(json);
104	  } catch {
105	    logger.warn('Failed to decrypt profile attributes', { profileId: profile.id });
106	    return {};
107	  }
108	}
