127	export async function importProfiles(
128	  data: string,
129	  format: 'json' | 'csv',
130	): Promise<ImportResult> {
131	  const errors: ValidationError[] = [];
132	  let profiles: Partial<FaceProfile>[] = [];
133	
134	  try {
135	    if (format === 'json') {
136	      const parsed = JSON.parse(data);
137	      profiles = Array.isArray(parsed) ? parsed : parsed.profiles ?? [];
138	    } else {
139	      const lines = data.split('\n').filter(l => l.trim());
140	      if (lines.length < 2) return { totalRecords: 0, importedCount: 0, skippedCount: 0, errors: [] };
141	      const headers = lines[0].split(',').map(h => h.trim());
142	      profiles = lines.slice(1).map(line => {
143	        const values = line.split(',').map(v => v.trim());
144	        const obj: Record<string, string> = {};
145	        headers.forEach((h, i) => { obj[h] = values[i] ?? ''; });
146	        return { name: obj.name, groupId: obj.group || obj.groupId, attributes: obj };
147	      });
148	    }
149	  } catch (e) {
150	    errors.push({ field: 'file', message: 'Failed to parse file', code: 'parse_error' });
151	    return { totalRecords: 0, importedCount: 0, skippedCount: 0, errors };
152	  }
153	
154	  let importedCount = 0;
155	  let skippedCount = 0;
156	
157	  for (const p of profiles) {
158	    if (!p.name) {
159	      skippedCount++;
160	      errors.push({ field: 'name', message: 'Profile missing name', code: 'required' });
161	      continue;
162	    }
163	    await enrollProfile(p.name, p.groupId, p.attributes ?? {});
164	    importedCount++;
165	  }
166	
167	  logger.info('Profiles imported', { total: profiles.length, imported: importedCount, skipped: skippedCount });
168	  return { totalRecords: profiles.length, importedCount, skippedCount, errors };
169	}
