49	export async function encryptAndStore(
50	  profileId: string,
51	  vector: Float32Array,
52	): Promise<EncryptedVector> {
53	  const dek = getCurrentDEK();
54	  if (!dek) {
55	    throw new Error('No encryption key available. User must be logged in.');
56	  }
57	
58	  const vectorString = JSON.stringify(Array.from(vector));
59	  const { ciphertext, iv } = await encrypt(vectorString, dek);
60	
61	  const now = new Date().toISOString();
62	  const record: EncryptedVector = {
63	    id: crypto.randomUUID(),
64	    profileId,
65	    encryptedData: arrayBufferToBase64(ciphertext),
66	    iv: uint8ArrayToBase64(iv),
67	    modelVersion: '1.0-local',
68	    extractedAt: now,
69	    createdAt: now,
70	    updatedAt: now,
71	    version: 1,
72	  };
73	
74	  await vectorRepo.add(record);
75	  logger.info('Vector encrypted and stored', { profileId });
76	  return record;
77	}
