32	  return arrayBufferToBase64(arr.buffer.slice(arr.byteOffset, arr.byteOffset + arr.byteLength));
33	}
34	
35	export function base64ToUint8Array(b64: string): Uint8Array {
36	  return new Uint8Array(base64ToArrayBuffer(b64));
37	}
38	
39	// --- Salt generation ---
40	
41	export function generateSalt(): Uint8Array {
42	  return crypto.getRandomValues(new Uint8Array(PBKDF2_SALT_LENGTH));
43	}
44	
45	// --- PBKDF2 password hashing ---
46	
47	async function importPasswordKey(password: string): Promise<CryptoKey> {
48	  return crypto.subtle.importKey(
49	    'raw',
50	    encoder.encode(password),
51	    'PBKDF2',
52	    false,
53	    ['deriveBits', 'deriveKey'],
54	  );
55	}
56	
57	export async function hashPassword(
58	  password: string,
59	  salt: Uint8Array,
60	): Promise<ArrayBuffer> {
61	  const baseKey = await importPasswordKey(password);
62	  return crypto.subtle.deriveBits(
63	    { name: 'PBKDF2', salt, iterations: PBKDF2_ITERATIONS, hash: 'SHA-256' },
64	    baseKey,
65	    AES_KEY_LENGTH,
66	  );
67	}
68	
69	export async function verifyPassword(
70	  password: string,
71	  salt: Uint8Array,
72	  expectedHash: ArrayBuffer,
73	): Promise<boolean> {
74	  const actualHash = await hashPassword(password, salt);
75	  const a = new Uint8Array(actualHash);
76	  const b = new Uint8Array(expectedHash);
77	  if (a.length !== b.length) return false;
78	  let diff = 0;
79	  for (let i = 0; i < a.length; i++) {
80	    diff |= a[i] ^ b[i];
81	  }
82	  return diff === 0;
83	}
84	
85	// --- Key derivation (KEK from password) ---
86	
87	export async function deriveKey(
88	  password: string,
89	  salt: Uint8Array,
90	): Promise<CryptoKey> {
91	  const baseKey = await importPasswordKey(password);
92	  return crypto.subtle.deriveKey(
93	    { name: 'PBKDF2', salt, iterations: PBKDF2_ITERATIONS, hash: 'SHA-256' },
94	    baseKey,
95	    { name: 'AES-GCM', length: AES_KEY_LENGTH },
96	    false,
97	    ['wrapKey', 'unwrapKey'],
98	  );
99	}
100	
101	// --- Data Encryption Key (DEK) ---
102	
103	export async function generateDataKey(): Promise<CryptoKey> {
104	  return crypto.subtle.generateKey(
105	    { name: 'AES-GCM', length: AES_KEY_LENGTH },
106	    true,
107	    ['encrypt', 'decrypt'],
108	  );
109	}
110	
111	// --- Key wrapping ---
112	
113	export async function wrapKey(
114	  dataKey: CryptoKey,
115	  wrappingKey: CryptoKey,
116	): Promise<{ wrapped: ArrayBuffer; iv: Uint8Array }> {
117	  const iv = crypto.getRandomValues(new Uint8Array(AES_IV_LENGTH));
118	  const wrapped = await crypto.subtle.wrapKey(
119	    'raw',
120	    dataKey,
121	    wrappingKey,
122	    { name: 'AES-GCM', iv },
123	  );
124	  return { wrapped, iv };
125	}
126	
127	export async function unwrapKey(
128	  wrapped: ArrayBuffer,
129	  iv: Uint8Array,
130	  wrappingKey: CryptoKey,
131	): Promise<CryptoKey> {
132	  return crypto.subtle.unwrapKey(
133	    'raw',
134	    new Uint8Array(wrapped),
135	    wrappingKey,
136	    { name: 'AES-GCM', iv },
137	    { name: 'AES-GCM', length: AES_KEY_LENGTH },
138	    true,
139	    ['encrypt', 'decrypt'],
140	  );
141	}
142	
143	// --- AES-GCM encrypt/decrypt ---
144	
145	export async function encrypt(
146	  data: string,
147	  key: CryptoKey,
148	): Promise<{ ciphertext: ArrayBuffer; iv: Uint8Array }> {
149	  const iv = crypto.getRandomValues(new Uint8Array(AES_IV_LENGTH));
150	  const ciphertext = await crypto.subtle.encrypt(
151	    { name: 'AES-GCM', iv },
152	    key,
153	    encoder.encode(data),
154	  );
155	  return { ciphertext, iv };
156	}
157	
158	export async function decrypt(
159	  ciphertext: ArrayBuffer,
160	  iv: Uint8Array,
161	  key: CryptoKey,
162	): Promise<string> {
163	  const plaintext = await crypto.subtle.decrypt(
164	    { name: 'AES-GCM', iv },
165	    key,
166	    ciphertext,
167	  );
168	  return decoder.decode(plaintext);
169	}
