1	import { releaseExpiredReservations } from '$modules/orders/order.service';
2	import { purgeExpired } from '$modules/files/recycle-bin.service';
3	import { processRetries } from '$modules/notifications/notification.service';
4	import { createLogger } from '$lib/logging';
5	
6	const logger = createLogger('app');
7	
8	export interface ReconciliationSummary {
9	  releasedReservations: number;
10	  purgedRecycleBin: number;
11	  processedRetries: number;
12	  scheduledNextRetries: number;
13	  skippedRetries: number;
14	}
15	
16	export async function reconcileOnStartup(
17	  now: Date = new Date(),
18	): Promise<ReconciliationSummary> {
19	  logger.info('Starting startup reconciliation', { timestamp: now.toISOString() });
20	
21	  // 1. Release expired reservations (free stock first)
22	  let releasedReservations = 0;
23	  try {
24	    const released = await releaseExpiredReservations(now);
25	    releasedReservations = released.length;
26	    if (releasedReservations > 0) {
27	      logger.info('Released expired reservations', { count: releasedReservations });
28	    }
29	  } catch (e) {
30	    logger.error('Failed to release expired reservations', { error: (e as Error).message });
31	  }
32	
33	  // 2. Purge expired recycle bin entries
34	  let purgedRecycleBin = 0;
35	  try {
36	    purgedRecycleBin = await purgeExpired(now);
37	    if (purgedRecycleBin > 0) {
38	      logger.info('Purged expired recycle bin entries', { count: purgedRecycleBin });
39	    }
40	  } catch (e) {
41	    logger.error('Failed to purge recycle bin', { error: (e as Error).message });
42	  }
43	
44	  // 3. Process overdue notification retries
45	  let processedRetries = 0;
46	  let scheduledNextRetries = 0;
47	  let skippedRetries = 0;
48	  try {
49	    const retryResult = await processRetries(now);
50	    processedRetries = retryResult.processed;
51	    scheduledNextRetries = retryResult.scheduledNext;
52	    skippedRetries = retryResult.skipped;
53	    if (processedRetries > 0) {
54	      logger.info('Processed overdue notification retries', retryResult);
55	    }
56	  } catch (e) {
57	    logger.error('Failed to process notification retries', { error: (e as Error).message });
58	  }
59	
60	  const summary: ReconciliationSummary = {
61	    releasedReservations,
62	    purgedRecycleBin,
63	    processedRetries,
64	    scheduledNextRetries,
65	    skippedRetries,
66	  };
67	
68	  logger.info('Startup reconciliation complete', summary);
69	  return summary;
70	}
