21	export async function checkDedup(sha256: string): Promise<{ exists: boolean; fileId?: string }> {
22	  const existing = await fileRepo.getByHash(sha256);
23	  const active = existing.find(f => !f.isDeleted);
24	  if (active) {
25	    return { exists: true, fileId: active.id };
26	  }
27	  return { exists: false };
28	}
