32	async function createUserInternal(
33	  username: string,
34	  password: string,
35	  role: UserRole,
36	  profile: UserProfile,
37	): Promise<User> {
38	  const salt = generateSalt();
39	  const passwordHashBuf = await hashPassword(password, salt);
40	  const kek = await deriveKey(password, salt);
41	  const dek = await generateDataKey();
42	  const { wrapped, iv } = await wrapKey(dek, kek);
43	
44	  const now = new Date().toISOString();
45	  const user: User = {
46	    id: crypto.randomUUID(),
47	    username,
48	    passwordHash: arrayBufferToBase64(passwordHashBuf),
49	    salt: uint8ArrayToBase64(salt),
50	    role,
51	    wrappedDEK: arrayBufferToBase64(wrapped),
52	    dekIV: uint8ArrayToBase64(iv),
53	    profile,
54	    createdAt: now,
55	    updatedAt: now,
56	    version: 1,
57	  };
58	
59	  await userRepo.add(user);
60	  logger.info('User created', { username, role });
61	  return user;
62	}
