88	export async function login(
89	  username: string,
90	  password: string,
91	): Promise<Session> {
92	  const user = await userRepo.getOneByIndex('username', username);
93	  if (!user) {
94	    throw new AuthenticationError('Invalid username or password');
95	  }
96	
97	  const salt = base64ToUint8Array(user.salt);
98	  const expectedHash = base64ToArrayBuffer(user.passwordHash);
99	  const valid = await verifyPassword(password, salt, expectedHash);
100	  if (!valid) {
101	    throw new AuthenticationError('Invalid username or password');
102	  }
103	
104	  const kek = await deriveKey(password, salt);
105	  const wrappedDEK = base64ToArrayBuffer(user.wrappedDEK);
106	  const dekIV = base64ToUint8Array(user.dekIV);
107	  currentDEK = await unwrapKey(wrappedDEK, dekIV, kek);
108	
109	  const now = new Date().toISOString();
110	  currentSession = {
111	    userId: user.id,
112	    role: user.role,
113	    loginAt: now,
114	    lastActivityAt: now,
115	    isLocked: false,
116	  };
117	
118	  logger.info('Login successful', { username, role: user.role });
119	  return currentSession;
120	}
