136	export async function unlock(password: string): Promise<Session> {
137	  if (!currentSession || !currentSession.isLocked) {
138	    throw new AuthenticationError('No locked session to unlock');
139	  }
140	
141	  const user = await userRepo.getById(currentSession.userId);
142	  if (!user) {
143	    throw new AuthenticationError('User not found');
144	  }
145	
146	  const salt = base64ToUint8Array(user.salt);
147	  const expectedHash = base64ToArrayBuffer(user.passwordHash);
148	  const valid = await verifyPassword(password, salt, expectedHash);
149	  if (!valid) {
150	    throw new AuthenticationError('Invalid password');
151	  }
152	
153	  const kek = await deriveKey(password, salt);
154	  const wrappedDEK = base64ToArrayBuffer(user.wrappedDEK);
155	  const dekIV = base64ToUint8Array(user.dekIV);
156	  currentDEK = await unwrapKey(wrappedDEK, dekIV, kek);
157	
158	  currentSession = {
159	    ...currentSession,
160	    isLocked: false,
161	    lastActivityAt: new Date().toISOString(),
162	  };
163	
164	  logger.info('Screen unlocked', { userId: currentSession.userId });
165	  return currentSession;
166	}
