171	export async function exportProfiles(
172	  profileIds: string[],
173	  format: 'json' | 'csv',
174	): Promise<string> {
175	  const profiles = profileIds.length > 0
176	    ? (await Promise.all(profileIds.map(id => getProfileById(id)))).filter(Boolean) as FaceProfile[]
177	    : await getProfiles();
178	
179	  if (format === 'json') {
180	    return JSON.stringify({
181	      formatVersion: '1.0',
182	      exportedAt: new Date().toISOString(),
183	      profiles: profiles.map(p => ({
184	        id: p.id, name: p.name, group: p.groupId,
185	        attributes: p.attributes, enrolledAt: p.enrolledAt,
186	      })),
187	    }, null, 2);
188	  }
189	
190	  // CSV
191	  const headers = ['id', 'name', 'group', 'enrolledAt'];
192	  const rows = profiles.map(p => [p.id, p.name, p.groupId ?? '', p.enrolledAt].join(','));
193	  return [headers.join(','), ...rows].join('\n');
194	}
