2	  import { getContext } from 'svelte';
3	  import Modal from '$components/Modal.svelte';
4	  import ProgressBar from '$components/ProgressBar.svelte';
5	  import { ingestFile, loadFiles, completeTransfer, pauseTransfer, resumeTransfer, ChunkScheduler, createVersion } from '$modules/files';
6	  import { getCurrentSession } from '$lib/security/auth.service';
7	  import { PreferenceStorage } from '$modules/preferences/storage';
8	  import { DEFAULT_BANDWIDTH_CAP } from '$lib/constants';
9	
10	  export let open = false;
11	
12	  const toast: any = getContext('toast');
13	
14	  let fileInput: HTMLInputElement;
15	  let selectedFile: File | null = null;
16	  let uploading = false;
17	  let progress = 0;
18	  let totalChunks = 0;
19	  let completedChunks = 0;
20	  let error = '';
21	  let deduplicated = false;
22	  let paused = false;
23	  let scheduler: ChunkScheduler | null = null;
24	  let sessionId: string | null = null;
25	
26	  function handleFileSelect(e: Event) {
27	    const target = e.target as HTMLInputElement;
28	    selectedFile = target.files?.[0] ?? null;
29	    deduplicated = false;
30	    error = '';
31	    progress = 0;
32	  }
33	
34	  async function handleConfirm() {
35	    if (uploading) return;
36	    if (!selectedFile) return;
37	    error = '';
38	    uploading = true;
39	    progress = 0;
40	    paused = false;
41	
42	    const userId = getCurrentSession()?.userId ?? 'unknown';
43	
44	    try {
45	      const buffer = await selectedFile.arrayBuffer();
46	      const result = await ingestFile(selectedFile.name, selectedFile.size, selectedFile.type, buffer, userId);
47	
48	      if (result.deduplicated) {
49	        deduplicated = true;
50	        toast?.addToast('File already exists (deduplicated)', 'info');
51	        uploading = false;
52	        await loadFiles();
53	        selectedFile = null;
54	        open = false;
55	        return;
56	      }
57	
58	      // Run real chunk scheduling
59	      if (result.session) {
60	        totalChunks = result.session.totalChunks;
61	        completedChunks = 0;
62	        sessionId = result.session.id;
63	        scheduler = new ChunkScheduler();
64	
65	        // Apply persisted bandwidth cap from settings
66	        const prefs = new PreferenceStorage();
67	        const savedCap = prefs.get<number>('bandwidth:cap');
68	        if (savedCap && savedCap > 0) {
69	          scheduler.setBandwidthCap(savedCap);
70	        }
71	
72	        await scheduler.scheduleChunks(result.session.id, buffer, (completed, total) => {
73	          completedChunks = completed;
74	          totalChunks = total;
75	          progress = Math.round((completed / total) * 100);
76	        });
77	
78	        // If paused mid-upload, don't complete — user can resume from Files page
79	        if (paused) {
80	          toast?.addToast('Upload paused. Resume from the Files page.', 'info');
81	          uploading = false;
82	          scheduler = null;
83	          sessionId = null;
84	          open = false;
85	          return;
86	        }
87	
88	        // Complete the transfer session
89	        await completeTransfer(result.session.id);
90	
91	        // Create first version
92	        await createVersion(result.file.id, result.file.sha256, result.file.size, userId);
93	      }
94	
95	      toast?.addToast(`File "${selectedFile.name}" uploaded (${totalChunks} chunks)`, 'success');
96	      await loadFiles();
97	      selectedFile = null;
98	      open = false;
99	    } catch (e: any) {
100	      error = e.message || 'Upload failed';
101	    } finally {
102	      uploading = false;
103	      scheduler = null;
104	      sessionId = null;
105	    }
106	  }
107	
108	  async function handlePause() {
109	    if (!scheduler || !sessionId) return;
110	    if (!paused) {
111	      scheduler.pause();
112	      await pauseTransfer(sessionId);
113	      paused = true;
114	    } else {
115	      await resumeTransfer(sessionId);
116	      scheduler.resume();
117	      paused = false;
118	    }
119	  }
