16	  fileStore.set(files.filter(f => !f.isDeleted));
17	}
18	
19	export async function loadTransfers(): Promise<void> {
20	  transferStore.set(await transferRepo.getAll());
21	}
22	
23	export async function optimisticDeleteFile(fileId: string, userId: string) {
24	  const current = get(fileStore);
25	  const optimistic = current.filter(f => f.id !== fileId);
26	
27	  return createOptimisticUpdate(fileStore, optimistic, async () => {
28	    await _deleteFile(fileId, userId);
29	    const files = await fileRepo.getAll();
30	    fileStore.set(files.filter(f => !f.isDeleted));
31	  });
32	}
33	
34	export async function optimisticRestoreFile(entryId: string) {
35	  return createOptimisticUpdate(fileStore, get(fileStore), async () => {
36	    await _restoreFile(entryId);
37	    const files = await fileRepo.getAll();
38	    fileStore.set(files.filter(f => !f.isDeleted));
39	  });
40	}
