  decryptBinary,       // <-- add
  arrayBufferToBase64,
  base64ToArrayBuffer,
  uint8ArrayToBase64,
  base64ToUint8Array,
} from './crypto';
```

#### File 3: `repo/frontend/src/lib/types/files.ts`

**Change**: Add `iv` field to `FileChunk` type and add `encryptedWithDEK` flag to `FileRecord`.

`FileChunk` (lines 14-19) becomes:

```ts
export interface FileChunk extends BaseEntity {
  fileId: string;
  chunkIndex: number;
  data: ArrayBuffer;
  size: number;
  iv?: string;  // Base64-encoded AES-GCM IV; present when chunk is encrypted
}
```

`FileRecord` (lines 4-12) becomes:

```ts
export interface FileRecord extends BaseEntity {
  name: string;
  mimeType: string;
  size: number;
  sha256: string;
  currentVersionId: string;
  createdBy: string;
  isDeleted: boolean;
  encryptedWithDEK?: boolean;  // true when chunks are encrypted with user's DEK
}
```

Using optional fields (`?`) ensures backward compatibility with existing unencrypted data in IndexedDB. When `iv` is absent on a chunk, it is treated as plaintext (legacy data). When `encryptedWithDEK` is absent on a FileRecord, it means the file was stored before encryption was added.

#### File 4: `repo/frontend/src/modules/files/chunk-scheduler.ts`

**Change**: Encrypt chunk data in `processChunk` before storing.

Add imports at the top of the file (after line 7):

```ts
import { getCurrentDEK } from '$lib/security/auth.service';
import { encryptBinary, uint8ArrayToBase64 } from '$lib/security/crypto';
```

Modify `processChunk` (lines 126-145). The current implementation stores raw data:

```ts
async processChunk(
  fileId: string,
  chunkIndex: number,
  data: ArrayBuffer,
): Promise<FileChunk> {
  const now = new Date().toISOString();

  // Encrypt chunk data with the user's DEK
  let storedData: ArrayBuffer = data;
  let iv: string | undefined;

  const dek = getCurrentDEK();
  if (dek) {
    const encrypted = await encryptBinary(data, dek);
    storedData = encrypted.ciphertext;
    iv = uint8ArrayToBase64(encrypted.iv);
  }

  const chunk: FileChunk = {
    id: crypto.randomUUID(),
    fileId,
    chunkIndex,
    data: storedData,
    size: data.byteLength,  // Store original (plaintext) size for reassembly
    iv,
    createdAt: now,
    updatedAt: now,
    version: 1,
  };

  await chunkRepo.add(chunk);
  return chunk;
}
```

Key design points:
- `size` still records the original plaintext byte count (needed by reassembly logic that allocates the output buffer).
- If `getCurrentDEK()` returns `null` (e.g., screen locked scenario -- though this shouldn't happen during upload since the user must be authenticated), the data is stored unencrypted as fallback, and `iv` is left `undefined`. This is a graceful degradation.
- The `iv` is stored as a base64 string alongside the chunk.

#### File 5: `repo/frontend/src/modules/files/file.service.ts`

**Change**: Set `encryptedWithDEK: true` on new `FileRecord` objects when DEK is available.

Add import at the top:

```ts
