#### File 6: `repo/frontend/src/routes/Files.svelte`

**Change**: Decrypt chunks when reassembling for preview in `openPreview`.

Add imports at the top (alongside existing crypto/auth imports):

```ts
import { getCurrentDEK } from '$lib/security/auth.service';
import { decryptBinary, base64ToUint8Array } from '$lib/security/crypto';
```

Modify `openPreview` (lines 110-131). The chunk reassembly loop (lines 115-123) needs to decrypt each chunk if it has an `iv`:

```ts
async function openPreview(fileId: string, mimeType: string, fileName: string) {
  const chunkRepo = new ChunkRepository();
  const chunks = await chunkRepo.getByFile(fileId);
  if (chunks.length > 0) {
    const sorted = chunks.sort((a, b) => a.chunkIndex - b.chunkIndex);
    const totalSize = sorted.reduce((sum, c) => sum + c.size, 0);
    const buffer = new ArrayBuffer(totalSize);
    const view = new Uint8Array(buffer);
    let offset = 0;

    const dek = getCurrentDEK();

    for (const chunk of sorted) {
      let chunkData: ArrayBuffer;
      if (chunk.iv && dek) {
        // Chunk is encrypted -- decrypt it
        const ivBytes = base64ToUint8Array(chunk.iv);
        chunkData = await decryptBinary(chunk.data, ivBytes, dek);
      } else {
        // Legacy unencrypted chunk or no DEK available
        chunkData = chunk.data;
      }
      view.set(new Uint8Array(chunkData), offset);
      offset += chunk.size;
    }
    previewData = buffer;
  } else {
    previewData = new ArrayBuffer(0);
  }
  previewMimeType = mimeType;
  previewFileName = fileName;
  showPreview = true;
}
```

#### File 7: `repo/frontend/src/routes/orders/DiscrepancyDrawer.svelte`

**Change**: Encrypt chunks when storing attachment payloads, and decrypt when downloading.

Add imports at the top of the `<script>` block:

```ts
import { getCurrentDEK } from '$lib/security/auth.service';
import { encryptBinary, decryptBinary, uint8ArrayToBase64, base64ToUint8Array } from '$lib/security/crypto';
```

**Encrypt in `filesToAttachments`** (lines 32-63). The chunk creation at lines 42-51 needs encryption:

```ts
async function filesToAttachments(files: FileList | null, discrepancyId: string): Promise<DiscrepancyAttachment[]> {
  if (!files) return [];
  const attachments: DiscrepancyAttachment[] = [];
  const now = new Date().toISOString();
  const dek = getCurrentDEK();

  for (const f of Array.from(files)) {
    const fileId = crypto.randomUUID();
    const data = await f.arrayBuffer();

    let storedData: ArrayBuffer = data;
    let iv: string | undefined;

    if (dek) {
      const encrypted = await encryptBinary(data, dek);
      storedData = encrypted.ciphertext;
      iv = uint8ArrayToBase64(encrypted.iv);
    }

    await chunkRepo.add({
      id: crypto.randomUUID(),
      fileId,
      chunkIndex: 0,
      data: storedData,
      size: data.byteLength,
      iv,
      createdAt: now,
      updatedAt: now,
      version: 1,
    });

    attachments.push({
      id: crypto.randomUUID(),
      discrepancyId,
      fileId,
      type: f.type || 'application/octet-stream',
      name: f.name,
      addedAt: now,
    });
  }

  return attachments;
}
```

**Decrypt in `downloadAttachment`** (lines 66-85). Modify the reassembly loop:

```ts
async function downloadAttachment(att: DiscrepancyAttachment) {
  const chunks = await chunkRepo.getByFile(att.fileId);
  if (chunks.length === 0) return;
  const sorted = chunks.sort((a, b) => a.chunkIndex - b.chunkIndex);
  const totalSize = sorted.reduce((sum, c) => sum + c.size, 0);
  const buffer = new ArrayBuffer(totalSize);
  const view = new Uint8Array(buffer);
  let offset = 0;

  const dek = getCurrentDEK();

  for (const chunk of sorted) {
    let chunkData: ArrayBuffer;
    if (chunk.iv && dek) {
      const ivBytes = base64ToUint8Array(chunk.iv);
      chunkData = await decryptBinary(chunk.data, ivBytes, dek);
    } else {
      chunkData = chunk.data;
    }
    view.set(new Uint8Array(chunkData), offset);
    offset += chunk.size;
  }

  const blob = new Blob([buffer], { type: att.type });
  const url = URL.createObjectURL(blob);
  const a = document.createElement('a');
  a.href = url;
  a.download = att.name;
  a.click();
  URL.revokeObjectURL(url);
}
```

#### File 8: `repo/frontend/src/routes/files/UploadModal.svelte`

No changes needed for encryption. The `UploadModal` calls `ChunkScheduler.scheduleChunks()` which internally calls `processChunk()`. Since `processChunk` now handles encryption transparently, the modal works without modification.

#### Test Impact

- The existing `unit_tests/security/crypto.test.ts` should get new tests for `encryptBinary`/`decryptBinary` (round-trip, wrong key throws, empty buffer).
- The existing `unit_tests/services/file-transfer.test.ts` tests `ChunkScheduler.processChunk` implicitly through `scheduleChunks`. These tests mock `getCurrentSession` but `getCurrentDEK` returns `null` via the mock (line 24). This means in tests, chunks will be stored unencrypted (graceful degradation path), so all existing tests continue to pass unchanged.
- New tests should verify: (a) when DEK is available, `processChunk` stores encrypted data with an `iv` field, (b) the stored ciphertext differs from the original data, (c) decryption with the same DEK yields the original data.
- The `unit_tests/services/discrepancy-attachments.test.ts` also mocks `getCurrentDEK` as `null`, so its tests continue to pass (unencrypted path).

#### Migration Note for Existing Data

Existing chunks in IndexedDB will not have the `iv` field. The decrypt logic explicitly checks `chunk.iv && dek` before attempting decryption. If `iv` is `undefined`/absent, the raw `chunk.data` is used directly. This provides seamless backward compatibility with pre-encryption data. No data migration is needed.

