1	import { VersionRepository, FileRepository } from '$lib/db';
2	import { ValidationServiceError } from '$lib/services/errors';
3	import { createLogger } from '$lib/logging';
4	import { enforceVersionLimit } from './retention';
5	import { NotificationType } from '$lib/types/enums';
6	import { dispatchNotification } from '$modules/notifications/notification.service';
7	import type { FileVersion } from '$lib/types/files';
8	
9	const versionRepo = new VersionRepository();
10	const fileRepo = new FileRepository();
11	const logger = createLogger('files');
12	
13	export async function createVersion(
14	  fileId: string,
15	  sha256: string,
16	  size: number,
17	  createdBy: string,
18	): Promise<{ version: FileVersion; removed: FileVersion[] }> {
19	  const existing = await versionRepo.getByFile(fileId);
20	  const maxVersion = existing.reduce((max, v) => Math.max(max, v.versionNumber), 0);
21	
22	  const now = new Date().toISOString();
23	  const newVersion: FileVersion = {
24	    id: crypto.randomUUID(),
25	    fileId,
26	    versionNumber: maxVersion + 1,
27	    sha256,
28	    size,
29	    createdBy,
30	    createdAt: now,
31	    updatedAt: now,
32	    version: 1,
33	  };
34	
35	  await versionRepo.add(newVersion);
36	
37	  // Update file's current version
38	  const file = await fileRepo.getById(fileId);
39	  if (file) {
40	    await fileRepo.put({
41	      ...file,
42	      currentVersionId: newVersion.id,
43	      updatedAt: now,
44	    });
45	  }
46	
47	  // Enforce retention limit
48	  const allVersions = await versionRepo.getByFile(fileId);
49	  const { remove } = enforceVersionLimit(allVersions);
50	
51	  for (const old of remove) {
52	    await versionRepo.delete(old.id);
53	  }
54	
55	  logger.info('Version created', {
56	    fileId,
57	    versionNumber: newVersion.versionNumber,
58	    removedCount: remove.length,
59	  });
60	
61	  return { version: newVersion, removed: remove };
62	}
63	
64	export async function rollbackToVersion(
65	  fileId: string,
66	  targetVersionId: string,
67	  createdBy: string,
68	): Promise<FileVersion> {
69	  const targetVersion = await versionRepo.getById(targetVersionId);
70	  if (!targetVersion) {
71	    throw new ValidationServiceError('Version not found', [
72	      { field: 'targetVersionId', message: 'Target version does not exist', code: 'not_found' },
73	    ]);
74	  }
75	
76	  if (targetVersion.fileId !== fileId) {
77	    throw new ValidationServiceError('Version mismatch', [
78	      { field: 'fileId', message: 'Version does not belong to this file', code: 'mismatch' },
79	    ]);
80	  }
81	
82	  const { version } = await createVersion(
83	    fileId,
84	    targetVersion.sha256,
85	    targetVersion.size,
86	    createdBy,
87	  );
88	
89	  logger.info('Version rolled back', {
90	    fileId,
91	    fromVersion: targetVersion.versionNumber,
92	    newVersion: version.versionNumber,
93	  });
94	
95	  try {
96	    await dispatchNotification(createdBy, NotificationType.FileVersionRollback, 'File Version Rolled Back',
97	      `File rolled back to version ${targetVersion.versionNumber}`,
98	      { fileId, fromVersion: targetVersion.versionNumber, newVersion: version.versionNumber });
99	  } catch { /* notification failure should not block rollback */ }
100	
101	  return version;
102	}
103	
104	export async function getVersionHistory(fileId: string): Promise<FileVersion[]> {
105	  const versions = await versionRepo.getByFile(fileId);
106	  return versions.sort((a, b) => b.versionNumber - a.versionNumber);
107	}
