1	import type { Permission, RevealCapability } from '$lib/types/auth';
2	import { UserRole } from '$lib/types/enums';
3	
4	const { Administrator, WarehouseManager, PickerPacker, Auditor } = UserRole;
5	const ALL_ROLES = [Administrator, WarehouseManager, PickerPacker, Auditor];
6	
7	export const PERMISSION_MATRIX: Permission[] = [
8	  { capability: 'identity.reveal_basic', roles: [Administrator, WarehouseManager] },
9	  { capability: 'identity.reveal_sensitive', roles: [Administrator] },
10	  { capability: 'files.reveal_key_metadata', roles: [Administrator] },
11	  { capability: 'users.reveal_contact', roles: [Administrator] },
12	];
13	
14	export const ROUTE_ACCESS: Record<string, UserRole[]> = {
15	  '/': ALL_ROLES,
16	  '/dashboard': ALL_ROLES,
17	  '/inventory': [Administrator, WarehouseManager, Auditor],
18	  '/inventory/ledger': [Administrator, WarehouseManager, Auditor],
19	  '/orders': [Administrator, WarehouseManager, PickerPacker],
20	  '/orders/waves': [Administrator, WarehouseManager, PickerPacker],
21	  '/files': [Administrator, WarehouseManager, Auditor],
22	  '/identity': [Administrator],
23	  '/notifications': ALL_ROLES,
24	  '/settings': ALL_ROLES,
25	};
26	
27	export const MUTATION_ACCESS: Record<string, UserRole[]> = {
28	  'inventory.create': [Administrator, WarehouseManager],
29	  'inventory.update': [Administrator, WarehouseManager],
30	  'inventory.transfer': [Administrator, WarehouseManager],
31	  'inventory.count': [Administrator, WarehouseManager, PickerPacker],
32	  'orders.create': [Administrator, WarehouseManager],
33	  'orders.update': [Administrator, WarehouseManager],
34	  'orders.pick': [Administrator, WarehouseManager, PickerPacker],
35	  'orders.pack': [Administrator, WarehouseManager, PickerPacker],
36	  'waves.plan': [Administrator, WarehouseManager],
37	  'tasks.start': [Administrator, WarehouseManager, PickerPacker],
38	  'tasks.complete': [Administrator, WarehouseManager, PickerPacker],
39	  'files.upload': [Administrator, WarehouseManager],
40	  'files.delete': [Administrator, WarehouseManager],
41	  'files.restore': [Administrator, WarehouseManager],
42	  'identity.enroll': [Administrator],
43	  'identity.import': [Administrator],
44	  'users.create': [Administrator],
45	  'users.update': [Administrator],
46	  'settings.update': [Administrator],
47	  'discrepancy.report': [Administrator, WarehouseManager, PickerPacker],
48	  'discrepancy.review': [Administrator, WarehouseManager],
49	  'discrepancy.resolve': [Administrator, WarehouseManager],
50	};
51	
52	export function canAccess(role: UserRole, route: string): boolean {
53	  const allowed = ROUTE_ACCESS[route];
54	  if (!allowed) return false;
55	  return allowed.includes(role);
56	}
57	
58	export function canMutate(role: UserRole, action: string): boolean {
59	  const allowed = MUTATION_ACCESS[action];
60	  if (!allowed) return false;
61	  return allowed.includes(role);
62	}
63	
64	export function canReveal(role: UserRole, capability: RevealCapability): boolean {
65	  const entry = PERMISSION_MATRIX.find(p => p.capability === capability);
66	  if (!entry) return false;
67	  return entry.roles.includes(role);
68	}
69	
70	export function isReadOnly(role: UserRole): boolean {
71	  return role === UserRole.Auditor;
72	}
