5	export class Repository<T extends BaseEntity> {
6	  constructor(protected readonly storeName: string) {}
7	
8	  async getById(id: string): Promise<T | undefined> {
9	    const db = getDb();
10	    return db.get(this.storeName, id) as Promise<T | undefined>;
11	  }
12	
13	  async getAll(): Promise<T[]> {
14	    const db = getDb();
15	    return db.getAll(this.storeName) as Promise<T[]>;
16	  }
17	
18	  async getByIndex(indexName: string, value: IDBValidKey): Promise<T[]> {
19	    const db = getDb();
20	    return db.getAllFromIndex(this.storeName, indexName, value) as Promise<T[]>;
21	  }
22	
23	  async getOneByIndex(indexName: string, value: IDBValidKey): Promise<T | undefined> {
24	    const db = getDb();
25	    return db.getFromIndex(this.storeName, indexName, value) as Promise<T | undefined>;
26	  }
27	
28	  async put(record: T): Promise<T> {
29	    const db = getDb();
30	    const updated = { ...record, version: (record.version || 0) + 1 };
31	    await db.put(this.storeName, updated);
32	    return updated as T;
33	  }
34	
35	  async add(record: T): Promise<T> {
36	    const db = getDb();
37	    await db.add(this.storeName, record);
38	    return record;
39	  }
40	
41	  async delete(id: string): Promise<void> {
42	    const db = getDb();
43	    await db.delete(this.storeName, id);
44	  }
45	
46	  async count(): Promise<number> {
47	    const db = getDb();
48	    return db.count(this.storeName);
49	  }
