62	export async function withTransaction<R>(
63	  storeNames: string[],
64	  mode: IDBTransactionMode,
65	  fn: (tx: IDBPTransaction<unknown, string[], typeof mode>) => Promise<R>,
66	): Promise<R> {
67	  const db = getDb();
68	  const tx = db.transaction(storeNames, mode);
69	  try {
70	    const result = await fn(tx);
71	    await tx.done;
72	    return result;
73	  } catch (error) {
74	    tx.abort();
75	    throw error;
76	  }
