2	import { DB_NAME, DB_VERSION, STORE_DEFINITIONS } from './schema';
3	
4	let db: IDBPDatabase | null = null;
5	
6	export async function initDatabase(): Promise<IDBPDatabase> {
7	  if (db) return db;
8	
9	  db = await openDB(DB_NAME, DB_VERSION, {
10	    upgrade(database) {
11	      for (const storeDef of STORE_DEFINITIONS) {
12	        if (!database.objectStoreNames.contains(storeDef.name)) {
13	          const store = database.createObjectStore(storeDef.name, {
14	            keyPath: storeDef.keyPath,
15	          });
16	          for (const index of storeDef.indexes) {
17	            store.createIndex(index.name, index.keyPath, index.options);
18	          }
19	        }
20	      }
21	    },
22	  });
23	
24	  return db;
25	}
26	
27	export function getDb(): IDBPDatabase {
28	  if (!db) {
29	    throw new Error('Database not initialized. Call initDatabase() first.');
30	  }
31	  return db;
32	}
33	
34	export function closeDb(): void {
35	  if (db) {
36	    db.close();
37	    db = null;
38	  }
39	}
