41	export async function resetDb(): Promise<void> {
42	  closeDb();
43	  await new Promise<void>((resolve, reject) => {
44	    const req = indexedDB.deleteDatabase(DB_NAME);
45	    req.onsuccess = () => resolve();
46	    req.onerror = () => reject(req.error);
47	    req.onblocked = () => resolve();
48	  });
49	}
