38	  async scheduleChunks(
39	    sessionId: string,
40	    fileData: ArrayBuffer,
41	    onProgress?: (completed: number, total: number) => void,
42	    versionId?: string,
43	  ): Promise<void> {
44	    const session = await transferRepo.getById(sessionId);
45	    if (!session) throw new ValidationServiceError('Session not found', [
46	      { field: 'sessionId', message: 'Not found', code: 'not_found' },
47	    ]);
48	
49	    // Set session to active
50	    await transferRepo.put({
51	      ...session,
52	      status: TransferState.Active,
53	      updatedAt: new Date().toISOString(),
54	    });
55	
56	    const totalChunks = session.totalChunks;
57	    // When a versionId is provided, scope deduplication to that version's chunks only.
58	    // This prevents prior version chunks from falsely marking indices as complete.
59	    const existingChunks = versionId
60	      ? await chunkRepo.getByVersion(versionId)
61	      : await chunkRepo.getByFile(session.fileId);
62	    const completedIndices = new Set(existingChunks.map(c => c.chunkIndex));
63	
64	    const pendingIndices: number[] = [];
65	    for (let i = 0; i < totalChunks; i++) {
66	      if (!completedIndices.has(i)) {
67	        pendingIndices.push(i);
68	      }
69	    }
70	
71	    // Process chunks with concurrency limit
72	    let completed = existingChunks.length;
73	
